const REPO_STATS_TTL_MS=24*60*60*1000;function getCachedRepoStats(repoName){try{const raw=localStorage.getItem(`repo-stats-${repoName}`);if(!raw)return null;const cached=JSON.parse(raw);if(Date.now()-cached.timestamp>REPO_STATS_TTL_MS){localStorage.removeItem(`repo-stats-${repoName}`);return null}
return cached.data}catch(error){return null}}
function cacheRepoStats(repoName,data){try{const payload={timestamp:Date.now(),data,};localStorage.setItem(`repo-stats-${repoName}`,JSON.stringify(payload))}catch(error){}}
function updateRepoStatsDOM(data,projectID){document.getElementById(`watch-${projectID}`).innerHTML=` ${data.watchers_count}`;document.getElementById(`star-${projectID}`).innerHTML=` ${data.stargazers_count}`;document.getElementById(`fork-${projectID}`).innerHTML=` ${data.forks_count}`;document.getElementById(`caption-${projectID}`).innerHTML=` ${data.description}`}
function setRepoStats(repoName,projectID){const cached=getCachedRepoStats(repoName);if(cached){updateRepoStatsDOM(cached,projectID);return}
const REPO_URL=`https://api.github.com/repos/inviro/${repoName}`;fetch(REPO_URL,{method:'GET',headers:{Accept:'application/json','Content-Type':'application/json','User-Agent':'AbrahamChen.com',},}).then((response)=>response.json()).then((data)=>{cacheRepoStats(repoName,data);updateRepoStatsDOM(data,projectID)}).catch(()=>{})}
function loadProject(entryID){const entry=document.getElementById(entryID);const title=entry.firstElementChild.innerHTML;const PROJECT_ID=entryID.split('-')[1];let result=`<a href = 'https://github.com/inviro/${title}'>${title}</a>`;entry.firstElementChild.innerHTML=result;result=`<a href="https://github.com/inviro/${title}/watchers" aria-label = "${title} Watchers"><i class="fa fa-lg fa-eye" id="watch-${PROJECT_ID}"></i></a>`;result+=`<a href="https://github.com/inviro/${title}/stargazers" aria-label = "${title} Stargazers"><i class="fa fa-lg fa-star" id="star-${PROJECT_ID}"></i></a>`;result+=`<a href="https://github.com/inviro/${title}/network/members" aria-label = "${title} Forks"><i class="fa fa-lg fa-code-branch" id="fork-${PROJECT_ID}"></i></a>`;document.getElementById(`repo-stats-${PROJECT_ID}`).innerHTML=result;setRepoStats(title,PROJECT_ID)}
function loadProjects(){const projects=document.getElementsByClassName('project');for(let i=0;i<projects.length;i++){loadProject(`project-${i}`)}}
function setThemeLight(){const root=document.documentElement;root.style.setProperty('--primary-color','3, 4, 94');root.style.setProperty('--overlay-color','rgba(245, 250, 255, 0.95)');root.style.setProperty('--header-color','33, 158, 188');root.style.setProperty('--highlight-color','rgba(255, 255, 255, .90)')}
function setThemeDark(){const root=document.documentElement;root.style.setProperty('--primary-color','255, 255, 255');root.style.setProperty('--overlay-color','rgba(50, 50, 140, .5)');root.style.setProperty('--header-color','3, 4, 94');root.style.setProperty('--highlight-color','#219EBC')}
function addThemePicker(){document.getElementById('theme-light').checked=!0;document.getElementById('color-theme').style.display='inline';document.getElementById('theme-light').onclick=setThemeLight;document.getElementById('theme-dark').onclick=setThemeDark}
function addAnimations(){const logo=document.getElementsByClassName('logo')[0];logo.addEventListener('mouseover',()=>{logo.style.animation='rotation 2s infinite linear'});logo.addEventListener('mouseout',()=>{logo.style.animation='none'})}
function addTextAnimation(ele,text){if(text.indexOf(' | ')>-1){let isPaused=!1;const wordArray=text.split(' | ');let currIdx=0;setInterval(()=>{if(!isPaused){ele.innerHTML=wordArray[currIdx];currIdx=((currIdx+1)%wordArray.length)}},4500);ele.addEventListener('mouseover',()=>{isPaused=!0});ele.addEventListener('mouseout',()=>{isPaused=!1})}}
function updateHitCount(){const a='aHR0cHM6Ly91cy1jZW50cmFsMS1hYnJhaGFtY2hlbndlYi5jbG91ZGZ1bmN0aW9ucy5uZXQvd2Vic2l0ZUhpdHMg';const visitsDisplay=document.getElementById('visits-display');fetch(atob(a)).then((resp)=>resp.json()).then((jsonResp)=>{let htmlString=`<p><strong>Weekly visits:  </strong>${parseInt(jsonResp.weeklyHits, 10).toLocaleString()}`;htmlString+=`<br><strong>Total visits:  </strong>${parseInt(jsonResp.totalHits, 10).toLocaleString()}</p>`;visitsDisplay.innerHTML=htmlString})}
let canvas,ctx,particles=[];function initParticles(){canvas=document.getElementById('particle-canvas');ctx=canvas.getContext('2d');canvas.width=window.innerWidth;canvas.height=window.innerHeight;for(let i=0;i<100;i++){particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-0.5)*2,vy:(Math.random()-0.5)*2,size:Math.random()*10+1,color:`rgba(255, 255, 255, ${Math.random()})`,})}
window.addEventListener('resize',()=>{canvas.width=window.innerWidth;canvas.height=window.innerHeight});animateParticles()}
function animateParticles(){ctx.clearRect(0,0,canvas.width,canvas.height);particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0||p.x>canvas.width)p.vx*=-1;if(p.y<0||p.y>canvas.height)p.vy*=-1;ctx.beginPath();ctx.arc(p.x,p.y,p.size,0,Math.PI*2);ctx.fillStyle=p.color;ctx.fill()});requestAnimationFrame(animateParticles)}
window.onload=()=>{updateHitCount();addThemePicker();addAnimations();loadProjects();initParticles()}